import{_ as o,I as e,o as s,c as b,at as _,J as t}from"./chunks/framework.DYZFTu11.js";const u=JSON.parse('{"title":"《α星篇·其八：『再燃烧吧』》","description":"","frontmatter":{},"headers":[],"relativePath":"zh_cn/novels/shuangxingluji/chapter-10.md","filePath":"zh_cn/novels/shuangxingluji/chapter-10.md","lastUpdated":1773498699000}'),c={name:"zh_cn/novels/shuangxingluji/chapter-10.md"};function i(l,r,p,h,d,g){const a=e("NolebaseGitContributors"),n=e("NolebaseGitChangelog");return s(),b("div",null,[r[0]||(r[0]=_('<h1 id="《α星篇·其八-『再燃烧吧』》" tabindex="-1"><strong>《α星篇·其八：『再燃烧吧』》</strong> <a class="header-anchor" href="#《α星篇·其八-『再燃烧吧』》" aria-label="Permalink to “《α星篇·其八：『再燃烧吧』》”">​</a></h1><p><strong>《α星篇·其八：『再燃烧吧』》</strong> 灵裔的攻势在幸存者小队愈发凌厉的反击下逐渐瓦解，残存的敌人如潮水般退去，只留下满地的尸骸和硝烟弥漫的战场。幸存者们喘息着，各自倚靠在大厅的断壁残垣旁，抓紧这短暂的休憩时刻。然而，空气中弥漫的不安却挥之不去——他们都知道，下一波攻势随时可能降临。<br> 叶子背靠一根断裂的石柱，指尖轻轻敲击着磁力步枪的枪身，目光警惕地扫视着四周。她的直觉向来敏锐，而此刻，某种异样的气息正悄然逼近。<br> 突然，她猛地抬头，枪口直指穹顶，厉声喝道：“什么人！”<br> 众人瞬间绷紧神经，武器齐刷刷对准上方。<br> 阴影中，一道人影缓缓浮现，仿佛从虚无中凝聚而成。她悬浮在半空，黑袍如夜般翻涌，苍白的面容上带着一抹令人不寒而栗的微笑。<br> “哼……哈哈哈……”阴冷的笑声在空旷的大厅内回荡，仿佛无数细小的虫豸爬过耳膜，令人毛骨悚然。<br> 叶子没有丝毫犹豫，直接扣下扳机。XG-7磁力重型步枪爆发出震耳欲聋的轰鸣，数枚足以撕裂钢甲的子弹呼啸而出，却在触及那黑影的瞬间如泥牛入海，连一丝涟漪都未能激起。<br> “……呵呵，我欣赏你们这副绝望的模样。”她轻声说道，声音如同毒蛇般滑腻。她的指尖微微抬起，地面上的尸体竟诡异地抽搐起来，骨骼扭曲，血肉蠕动，一具具行尸走肉摇摇晃晃地站了起来。<br> “该死！”叶子咒骂一声，一边向后疾退，一边朝尸群倾泻火力，“哪来这么多尸体？我们根本没杀过这么多人！”<br> 尼尔德猛地拽住她的手臂，将她狠狠拉向一旁。下一秒，一道血色藤蔓如长矛般刺穿她原先站立的位置，地面被撕裂出一道狰狞的裂痕。<br> “你这骂街不躲子弹的毛病能不能改改！”尼尔德怒吼道，手中的磁力步枪已经因过热而泛红。<br> 幸存者们的处境愈发危急。他们的体力早已濒临极限，而身后的尸潮却如海浪般无穷无尽。更可怕的是，那个黑影仍在不断释放魔法，血色藤蔓如毒蛇般从地面窜出，逼迫他们疲于奔命。<br> “糟了！”尼尔德侧身闪过又一记藤蔓突刺，冲叶子喊道，“再这样下去我们都得完蛋！”<br> 叶子一枪轰碎某个活死人的头颅，咬牙回应：“我能有什么办法？！她现在根本就是在戏弄我们，就像对待实验品一样——星溯，快闪开！”<br> 队伍中央的星溯闻声猛然侧身，一道猩红藤蔓几乎贴着她的脖颈掠过，带起的劲风在她皮肤上留下一道细小的血痕。<br> “差一点就……”她心有余悸地喃喃道，冷汗顺着额角滑落。<br> 然而，这份庆幸还未持续一秒——<br> “轰！”<br> 剧烈的爆炸骤然撕裂墙壁，碎石与烟尘四散飞溅。无数灵裔战士从烟尘中蜂拥而出，冰冷的铠甲在昏暗的光线下泛着森冷的光泽。<br> 叶子回头瞥见这一幕，瞳孔骤缩：“是灵裔！增援到了！”<br> 疲惫不堪的幸存者们被迫迎战，但在人数与体力的双重劣势下，败局已定。枪声、怒吼声、骨骼碎裂声交织在一起，鲜血在地面上蜿蜒流淌，宛如一幅残酷的画卷。<br> “又倒下一个！快想点办法！”尼尔德手中的磁力步枪因过热而嗡鸣不止，面前的尸群倒下又爬起，仿佛永无止境。<br> 叶子咬紧牙关，突然从腰间取出一支闪烁着幽蓝光芒的药剂，猛地抛向星溯。<br> “接着！”<br> 星溯下意识地接住药剂，一股灼热的熟悉感瞬间从掌心蔓延至全身，仿佛它与自己的血脉相连。混乱的记忆碎片如潮水般涌入脑海，陌生的画面与声音交织在一起，令她头痛欲裂。<br> “听着……这是你父亲留下的。”叶子的声音低沉而决绝，“它能让你恢复‘原本的姿态’。我本不想交给你……但眼下别无选择了。”<br> 她顿了顿，目光如炬。<br> “记住他的警告：不要相信低语。”<br> 星溯握紧药剂，指节因用力而发白。恍惚间，她仿佛听到一个遥远的声音在耳畔低语，如风如雾，却又无比清晰——<br> “『再燃烧吧』。”</p>',2)),t(a),t(n)])}const f=o(c,[["render",i]]);export{u as __pageData,f as default};
